var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"唉……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"남들은 다큐멘터리에서나 보는 이면세계를 벌써 두 번이나 오게 되다니......","JPN":"普通の人は、テレビでしか見たことがない裏世界に二度も訪れませんよ……","ENG":"So I'm here again in the Counterside, a place most people only see in documentaries...","TWN":"我們居然來了兩次異界，就像別人看的紀錄片那樣……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이걸 좋아해야 할지 싫어해야 할지 모르겠네요.","JPN":"これを喜ぶべきか、悲しむべきか……","ENG":"I'm not sure if this is a good thing or a bad thing.","TWN":"真不知道是該喜歡還是討厭呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님 생각은 어떠세요?","JPN":"警視様はどう思います？","ENG":"Any thoughts, Major?","TWN":"妳是怎麼想的呢，警正？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"우리는......","JPN":"私たちは……","ENG":"We're...","TWN":"我們是……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네, 네. 경찰이죠, 경찰.","JPN":"はいはい、警察ですよね、警察。","ENG":"Yeah, yeah. We're the police, I know.","TWN":"對，對，我們是警察啦，警察。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 경찰이라고 해서 세상 모든 일에 책임을 져야 하는 건 아니잖아요?","JPN":"でも警察だからって、世の中に起きてることすべてに責任を負う必要はないでしょう？","ENG":"But the police don't have to be responsible for everything that happens in this world.","TWN":"但就算我們是警察，也不用對世界上所有的事情負責吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우리에겐 규정도 있고 규칙도 있어요.","JPN":"我々にもルールがあり、規則がありますよね。","ENG":"We have rules and regulations for a reason.","TWN":"我們也是有原則，有規定的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"한계를 벗어난 일을 억지로 떠안는 것보다......","JPN":"キャパ以上の仕事を強引にやらされるより……","ENG":"It's important that we acknowledge out limits.","TWN":"比起做超出能力範圍的事情……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"제대로 된 전문가들에게 맡기는 게 더 나은 경우도 분명히 있다고요.","JPN":"ちゃんとしたプロに任せたほうがいい場合もあるんですよ。","ENG":"There are things that's much better left to the experts.","TWN":"還是交給專業人士比較好吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그 정도는 이제 알 나이도 됐잖아요?","JPN":"もうそろそろ、それくらいはわかる時期なんじゃないですか？","ENG":"Aren't you old enough to know that?","TWN":"現在妳也到該懂這種事的年紀了吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"That's...","TWN":"呃……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"미안해, 강소영 경위.","JPN":"ごめん、マエカワ警部補。","ENG":"I'm sorry, Lieutenant.","TWN":"抱歉，姜素英警衛。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내가 고집을 부린 건...... 사실......","JPN":"私が今回強引に進めたのは……実は……","ENG":"I insisted that we come here because...","TWN":"我是裝作逞強的樣子……事實上……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저, 저기요!","JPN":"あ、あのー！","ENG":"U-um... Excuse me?","TWN":"那、那個！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저기 그...... 어보미...... 뭐라는 걸 찾은 것 같아요.","JPN":"あの、その……アボミなんとかを見つけたみたいです。","ENG":"I think I've found that Abomi... thing.","TWN":"在那邊……憎什麼……我好像找到那個憎什麼的東西了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"이, 이제 어쩌죠?","JPN":"こ、ここからはどうすれば？","ENG":"W-what do we do now?","TWN":"那現、現在該怎麼辦？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......하아.","JPN":"……はあ。","ENG":"*Sigh*","TWN":"……唉。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 어쩔 수 없네요.","JPN":"ははは、仕方ないですね。","ENG":"I guess we have no choice.","TWN":"哈哈，真是沒辦法呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"잔소리는 이따가 하도록 하죠.","JPN":"小言は後にしましょう。","ENG":"I'll save the nagging for later.","TWN":"說教就等之後再說吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어차피 여기까지 왔으니 어떻게든 끝을 봐야 하지 않겠어요?","JPN":"せっかくここまで来たんですから、なんとかケリをつけないと。","ENG":"We've come this far, and we can't go back without putting an end to this.","TWN":"反正都來到這裡了，總要做個了斷吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위......","JPN":"マエカワ警部補……","ENG":"Lieutenant...","TWN":"姜素英警衛……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그래서, 적은 어디에 있죠?","JPN":"それで、敵はどこですか？","ENG":"So, where's our enemy?","TWN":"所以說，敵人在哪裡啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그게......","JPN":"そ、それが……","ENG":"W-well...","TWN":"那、那個……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"적이 하나가 아니에요......","JPN":"敵は単体ではありません……","ENG":"It's \\"enemies.\\"","TWN":"敵人不止一個……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네? 무슨 말이죠?","JPN":"え？　どういうことでしょう？","ENG":"Sorry? What do you mean?","TWN":"咦？妳說什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"여, 여기 오기 전에 미나 씨가 말해 준 대로 특이 침식파 반응이 나타났어요......","JPN":"こ、ここに来る前にミナさんが言っていたとおり、特異侵食波の反応がありました……","ENG":"We're getting a unique Corruption ray response, just like Mina told us about before we came here.","TWN":"就、就像來之前米娜小姐說的那樣，出現了特異侵蝕波反應……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"설마...... 그림자 말인가요?","JPN":"まさか……シャドウですか？","ENG":"You mean... the Shadow?","TWN":"妳該不會……是在說暗影？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그런 것 같아요......","JPN":"そ、そのようです……","ENG":"Th-that's what I'm thinking.","TWN":"好、好像是這樣……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저희들은 이면세계에 처음 다이브 하는 거라서......","JPN":"ヒミコたちは裏世界へのダイブが初めてで……","ENG":"This is our first dive into the Counterside.","TWN":"因為我們是第一次躍入異界……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"어쩌면 나올지도 모른다고 듣긴 했는데......","JPN":"もしかしたら出現するかもしれないとは聞いていましたが……","ENG":"We heard that something like this could happen,","TWN":"所以聽說那搞不好會出現……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"정말 나타날 줄은......","JPN":"まさか本当に現れるとは……","ENG":"but never did we think that it would for real.","TWN":"結果它就真的……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"끄응......","JPN":"うわぁ……","ENG":"*Sigh*","TWN":"呃。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"엎친 데 덮친 격이라더니......","JPN":"泣きっ面に蜂ですね……","ENG":"This is bad...","TWN":"這還真是雪上加霜啊……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"왜 항상 확률이란 건 최악의 상황만 골라서 터지는 건지 모르겠네요.","JPN":"最悪なことって、どうしていつも立て続けに起こるんですかね。","ENG":"Why does every case I undertake have to turn out like this?","TWN":"真不知道為什麼我每次都會遇到最糟糕的情況。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"여, 역시 우리들 힘만으로는 어렵겠죠?","JPN":"や、やっぱり、秋たちだけで討伐するのは無理そうですよね？","ENG":"W-we can't take them on by ourselves, can we?","TWN":"只、只靠我們的力量果然很難吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그러니까 이, 일단은 돌아가서 다시 준비를......","JPN":"一旦帰って、出直したほうが……","ENG":"I guess we'll have to get back and prepare for—","TWN":"所以說啊，我們要不要先回去重新準備……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 여러분은 아까 휴게실에서 쉬느라 작전 설명을 못 들었죠?","JPN":"あ、そうか。皆さんはさっき休憩室で休んでて、作戦説明を聞いてないんですよね？","ENG":"Ah, you weren't there when Mr. Finley was briefing us on the operation, were you?","TWN":"啊，你們剛剛在休息室休息，所以沒聽到作戰說明吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그게...... 우리가 타고 온 강하선에는 사실 귀환 기능이 없거든요.","JPN":"実は……私たちが乗ってきた降下船には、帰還機能がないんです。","ENG":"As a matter of fact, the drop ship we did the dive in isn't capable of getting us out of here.","TWN":"這個嘛……事實上，我們所乘坐的降落艙呢，是沒有返航功能的喔。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"히익! 뭐라고요?!","JPN":"ひいっ！　何ですって！？","ENG":"Eeek! What did you say?","TWN":"咿！妳說什麼？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"따, 딸꾹?!!","JPN":"ひぃぃ！！？","ENG":"*Hiccup*","TWN":"欸欸？！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"돌아가려면 위에서 구조선을 보내줘야 해요.","JPN":"ですから、上から救助船を送ってくれなきゃ帰れないんです。","ENG":"The only way back is through the rescue ship from the Normalside.","TWN":"要回去的話，就得等上級派救援艦船過來才行。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그러니까 위에서 구조선을 보내줄 마음이 들도록 열심히 해야겠죠?","JPN":"早く救助船を送ってもらうためには、頑張らないといけませんね？","ENG":"And they won't send it unless they are very happy with our performance here.","TWN":"所以為了讓上級願意派救援艦船過來，我們就必須努力一下囉？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"마, 말도 안 돼!!","JPN":"そ、そんな！！","ENG":"N-no way!","TWN":"不要啊！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"제 눈에서 뭔가 흐르는 것 같아요......","JPN":"秋、目から何かが流れてきた気が……","ENG":"Th-there's something running down my face.","TWN":"我眼裡好像流出了什麼……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"이게 피눈물이라는 걸까요?","JPN":"ちょっと泣いてもいいですか？","ENG":"And I guarantee you, it's not sweat.","TWN":"這難道就是辛酸的血淚嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자자, 걱정하지 말아요.","JPN":"まあまあ、そんなに心配しないで。","ENG":"Now, don't worry.","TWN":"好了好了，大家不要擔心啦。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어쩌면 상황이 그리 나쁘지만은 않을 수도 있으니까요.","JPN":"もしかしたら、そこまで悪い状況ではないかもしれませんよ？","ENG":"This situation may not be as bad as it seems.","TWN":"這個狀況說不定也沒有那麼糟。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭔가 작전이라도 있는 거야, 강소영 경위?","JPN":"何か良い作戦でもあるの？　マエカワ警部補。","ENG":"Do you have a plan, Lieutenant?","TWN":"妳有什麼作戰計畫啊，姜素英警衛？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이이제이라는 말이 있죠.","JPN":"「毒をもって毒を制す」という言葉もありますよね。","ENG":"We'll use our enemies against each other.","TWN":"聽說過以夷制夷這句話吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그림자와 어보미네이션도 딱히 같은 편은 아닐 거에요.","JPN":"シャドウとアボミネーションは、とくに味方ではないと思うんです。","ENG":"I doubt the Shadow and Abomination are on friendly terms.","TWN":"暗影和憎惡也不一定是站在同一邊的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"서로 싸우게 만들기만 하면 둘 다 쉽게 처리할 수 있겠죠.","JPN":"お互いにケンカさせておけば、いずれも簡単に始末できるかと。","ENG":"If we could play one off against the other, things will be a lot easier.","TWN":"所以，只要能製造出讓他們自相殘殺的局面，就可以輕鬆解決掉他們兩個了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"조, 좋은 생각이에요!","JPN":"ナ、ナイスアイディアですね！","ENG":"Th-that’s a wonderful idea!","TWN":"這，這真是個好主意！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그런데...... 어떻게 둘이 싸우게 만들죠?","JPN":"でも……ケンカさせるにはどうすれば？","ENG":"So... How are we going to do that?","TWN":"可是……我們要怎麼讓他們兩個打起來呢？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그야 우리가 미끼가 돼서 유인해 와야죠.","JPN":"そりゃ、私たちがエサになっておびき寄せるんです。","ENG":"We'll be the bait and pull them close to each other.","TWN":"那就要我們當誘餌把他們引誘過來囉。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"네, 네?","JPN":"え、ええっ！？","ENG":"E-excuse me?","TWN":"什、什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히이익!!","JPN":"ひいいっ！！","ENG":"Hic!","TWN":"咿咿咿！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우리들 중에 최고 전력은 경정님이에요.","JPN":"この中で最高戦力は警視様です。","ENG":"Major Lee here is the best card we've got.","TWN":"我們之中戰鬥力最高的是警正。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우리가 먼저 저 괴물들의 주의를 끌게 되면 경정님이 난입해서 결착을 내 주셔야 해요.","JPN":"私たちが先にあいつらの注意を引いたら、警視様が登場して決着をつけるんです。","ENG":"We go in, draw the attention of the monsters, then Major comes in and wipes out whatever is left of them.","TWN":"所以我們就先去吸引那些怪物的注意，然後警正從中殺出，把它們通通解決掉。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"너무 늦으면 우린 두 괴물들 사이에서 햄버거 패티 꼴이 되어 버릴 거에요.","JPN":"登場が遅れたら、私たちは双方に挟まれ、ハンバーガーのパティ状態になるでしょうね。","ENG":"And Major, you'd better be on time, or we're going to be squashed like marshmallows.","TWN":"要是警正來太晚了，那我們就會變成兩隻怪物中間的夾心餅乾了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......알겠죠?","JPN":"……以上、わかりましたか？","ENG":"Okay?","TWN":"知道了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......알았어.","JPN":"……わかった。","ENG":"Okay.","TWN":"……知道了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내게 맡겨.","JPN":"私に任せて。","ENG":"Don't worry.","TWN":"交給我吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"반드시 해낼 테니까.","JPN":"必ずやり遂げてみせる。","ENG":"I won't let you die.","TWN":"我一定會成功的！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"좋아요. 다들 준비됐죠?","JPN":"よし、みんな準備はいいですね？","ENG":"Good. Everyone ready?","TWN":"很好。那大家都準備好了吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"또, 또 이런 꼴이야......","JPN":"またもやこんなハメに……","ENG":"I-I can't believe I'm doing something so insane again...","TWN":"又來了，又是這個樣子……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"미나 양을 믿는 게 아니었어......","JPN":"ミナさんのこと、信じるんじゃありませんでした。","ENG":"I shouldn't have trusted Mina!","TWN":"不該相信米娜小姐的……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"까짓 거 한 번 죽지 두 번 죽겠어요?","JPN":"ここまで来たら、一か八かやってみるしかないでしょ。","ENG":"Come on, you can only die once, people.","TWN":"大不了就死掉而已嘛。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"갑시다!","JPN":"行きましょう！","ENG":"Let's go!","TWN":"我們上吧！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};